// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Set;

import org.junit.jupiter.api.Test;

class SearchWorkLedgerTest {

	@Test
	void ruleWorkStopsBeforeOvershoot() {
		SearchWorkLedger ledger = new SearchWorkLedger(limits(1L, 10L, 10L, 10L));

		assertTrue(ledger.tryRuleWork());
		SearchCounterSnapshot atLimit = ledger.counterSnapshot();
		assertEquals(1L, atLimit.ruleWork());

		assertFalse(ledger.tryRuleWork());
		assertFalse(ledger.tryRuleWork());
		assertEquals(atLimit, ledger.counterSnapshot(), "denied work must not increment the reported counter");
		assertEquals(Set.of(OptimizationLimitCause.RULE_WORK), ledger.limitCauses());
	}

	@Test
	void dphypAndTotalPartitionChargeIsAtomic() {
		SearchWorkLedger ledger = new SearchWorkLedger(limits(10L, 1L, 2L, 10L));

		assertTrue(ledger.tryDphypPairProbe());
		SearchCounterSnapshot afterFirstProbe = ledger.counterSnapshot();
		assertEquals(1L, afterFirstProbe.dphypPairProbes());
		assertEquals(1L, afterFirstProbe.partitionProbes());

		assertFalse(ledger.tryDphypPairProbe());
		assertEquals(afterFirstProbe, ledger.counterSnapshot(),
				"when either DPhyp or total capacity is exhausted, neither counter may advance");
		assertEquals(Set.of(OptimizationLimitCause.DPHYP_PAIR_PROBES), ledger.limitCauses());

		assertTrue(ledger.tryPartitionProbe(), "generic exact search may consume the remaining total capacity");
		assertEquals(1L, ledger.counterSnapshot().dphypPairProbes());
		assertEquals(2L, ledger.counterSnapshot().partitionProbes());
	}

	@Test
	void retentionEvictionUpdatesOccupancyAndHighWater() {
		SearchWorkLedger ledger = new SearchWorkLedger(limits(10L, 10L, 10L, 2L));

		assertTrue(ledger.tryRetainCandidate());
		ledger.observeFrontierSize(1L);
		assertTrue(ledger.tryRetainCandidate());
		ledger.observeFrontierSize(2L);
		ledger.releaseRetainedCandidate();

		SearchRetentionSnapshot retention = ledger.retentionSnapshot();
		assertEquals(1L, retention.currentRetainedCandidates());
		assertEquals(2L, retention.retainedCandidateHighWaterMark());
		assertEquals(2L, retention.frontierHighWaterMark());
		assertTrue(ledger.limitCauses().isEmpty(), "ordinary dominance eviction is not a limit cause");
	}

	@Test
	void multipleLimitCausesArePreserved() {
		SearchWorkLedger ledger = new SearchWorkLedger(limits(0L, 0L, 0L, 0L));

		assertFalse(ledger.tryRuleWork());
		assertFalse(ledger.tryDphypPairProbe());
		assertFalse(ledger.tryRetainCandidate());
		ledger.recordFrontierTruncation();
		assertFalse(ledger.tryRuleWork(), "recording the same cause twice must remain idempotent");

		Set<OptimizationLimitCause> causes = ledger.limitCauses();
		assertEquals(Set.of(
				OptimizationLimitCause.RULE_WORK,
				OptimizationLimitCause.DPHYP_PAIR_PROBES,
				OptimizationLimitCause.PARTITION_PROBES,
				OptimizationLimitCause.RETAINED_STATE,
				OptimizationLimitCause.FRONTIER_TRUNCATION), causes);
		assertThrows(UnsupportedOperationException.class,
				() -> causes.add(OptimizationLimitCause.DEADLINE), "the result-boundary cause set must be immutable");
		assertEquals(SearchCounterSnapshot.ZERO, ledger.counterSnapshot());
		assertEquals(SearchRetentionSnapshot.ZERO, ledger.retentionSnapshot());
	}

	private static SearchLimits limits(long ruleWork, long dphypPairProbes, long partitionProbes,
			long retainedCandidates) {
		return new SearchLimits(ruleWork, dphypPairProbes, partitionProbes, 10L, 10L, retainedCandidates, 3L);
	}
}
